-- US-053 — RPC backing the create-listing edge function.
--
-- Contract: public.create_listing_rpc(
--   p_lister_id uuid,
--   p_payload  jsonb
-- ) returns jsonb.
--
-- Payload shape (validated at the edge):
--   {
--     title:            text,
--     description:      text,
--     price_cents:      int,
--     currency:         text,
--     max_submissions:  int | null,
--     pre_conditions:   [{ platform, metric, threshold }],  -- platform ∈ tiktok|instagram,
--                                                          -- metric ∈ followers|avg_views
--     post_conditions:  [{ id (uuid), text }],              -- id minted by wizard
--     sample_videos:    [{ platform, url }]
--   }
--
-- On success: {"listing_id": "<uuid>", "version_id": "<uuid>"}.
--
-- Transaction flow:
--   1. INSERT listings (status='active', published_at=now(), min_followers_*
--      cache columns populated from the payload's pre_conditions — spec §15b
--      triggers are still scoped out per progress.txt Codebase Pattern #52, so
--      every caller that writes listings has to populate the cache inline).
--   2. INSERT listing_versions (version_number=1, snapshot=to_jsonb(inserted
--      listing row with current_version_id=null at this point)).
--   3. INSERT listing_conditions rows (both kinds; post-conditions reuse the
--      wizard-minted uuid so the submit-video affirmation map keys survive
--      round-trip per docs/tech-architecture.md §5.6).
--   4. INSERT sample_videos rows.
--   5. UPDATE listings.current_version_id = new_version_id.
--      Trigger trg_bump_listing_version fires on this UPDATE but versioned_
--      changed is false (price/currency/max/version_bump_reason all unchanged),
--      so it passes through without creating a duplicate version row.
--
-- Post-condition metric mapping:
--   The wizard captures free-text post-conditions; condition_metric enum has no
--   generic "free-text rule" value. We store every post-condition as
--   metric='post_must_mention' + operator='contains' + text_threshold=<text>.
--   The submit-video edge function only keys off condition row.id when mapping
--   affirmations (supabase/functions/submit-video/index.ts:209-211) so the
--   specific metric value does not affect runtime semantics; it just ensures
--   the row satisfies the enum CHECK. The UI reads text_threshold for display.
--
-- Spec gap: the condition_metric enum lacks a generic free-text post-condition
-- value (see progress.txt). Documented here + in the edge function header.
--
-- Auth: revoked from anon/authenticated/public. Only service_role (used by the
-- create-listing edge function) may execute.

create or replace function public.create_listing_rpc(
  p_lister_id uuid,
  p_payload   jsonb
) returns jsonb
language plpgsql
set search_path = ''
as $$
declare
  v_listing_id         uuid;
  v_version_id         uuid;
  v_min_tt             integer;
  v_min_ig             integer;
  v_pre_rows           jsonb;
  v_post_rows          jsonb;
  v_sample_rows        jsonb;
  v_pre                jsonb;
  v_post               jsonb;
  v_sample             jsonb;
  v_metric             public.condition_metric;
  v_platform           public.platform;
  v_sort               smallint := 0;
  v_price_cents        integer;
  v_currency           text;
  v_max_submissions    integer;
  v_title              text;
  v_description        text;
begin
  -- Hoist payload scalars; the edge function has already shape-validated, but
  -- defensive casts keep this RPC safe if a future caller forgets.
  v_title           := p_payload ->> 'title';
  v_description     := p_payload ->> 'description';
  v_price_cents     := (p_payload ->> 'price_cents')::integer;
  v_currency        := p_payload ->> 'currency';
  v_max_submissions := nullif(p_payload ->> 'max_submissions', '')::integer;
  v_pre_rows        := coalesce(p_payload -> 'pre_conditions',  '[]'::jsonb);
  v_post_rows       := coalesce(p_payload -> 'post_conditions', '[]'::jsonb);
  v_sample_rows     := coalesce(p_payload -> 'sample_videos',   '[]'::jsonb);

  -- Compute cache columns from the payload so the discover feed's threshold
  -- filter (us_038) sees correct values on first publish without depending on
  -- §15b triggers that are still out-of-scope.
  select max((row_data ->> 'threshold')::integer)
    into v_min_tt
    from jsonb_array_elements(v_pre_rows) as row_data
   where row_data ->> 'platform' = 'tiktok'
     and row_data ->> 'metric'   = 'followers';

  select max((row_data ->> 'threshold')::integer)
    into v_min_ig
    from jsonb_array_elements(v_pre_rows) as row_data
   where row_data ->> 'platform' = 'instagram'
     and row_data ->> 'metric'   = 'followers';

  insert into public.listings (
    lister_id, status, title, description, price_cents, currency,
    max_submissions, min_followers_tiktok, min_followers_instagram,
    published_at
  ) values (
    p_lister_id,
    'active'::public.listing_status,
    v_title, v_description, v_price_cents, v_currency,
    v_max_submissions, v_min_tt, v_min_ig,
    now()
  )
  returning id into v_listing_id;

  insert into public.listing_versions (
    listing_id, version_number, price_cents, currency, max_submissions,
    snapshot, previous_version_id, changed_fields
  )
  select v_listing_id, 1, v_price_cents, v_currency, v_max_submissions,
         to_jsonb(l.*), null, array[]::text[]
    from public.listings l
   where l.id = v_listing_id
  returning id into v_version_id;

  -- Pre-conditions: map wizard shape → listing_conditions rows.
  for v_pre in select * from jsonb_array_elements(v_pre_rows)
  loop
    v_platform := (v_pre ->> 'platform')::public.platform;
    v_metric := case v_pre ->> 'metric'
                  when 'followers' then 'min_followers'::public.condition_metric
                  when 'avg_views' then 'min_avg_views_last_n'::public.condition_metric
                  else null
                end;
    if v_metric is null then
      raise exception 'invalid pre-condition metric: %', v_pre ->> 'metric';
    end if;

    insert into public.listing_conditions (
      listing_version_id, kind, metric, platform, operator, numeric_threshold
    ) values (
      v_version_id,
      'pre'::public.condition_kind,
      v_metric,
      v_platform,
      'gte',
      (v_pre ->> 'threshold')::numeric
    );
  end loop;

  -- Post-conditions: reuse the wizard-minted uuid so the per-rule affirmation
  -- keys in submit-video remain stable across wizard → publish → submit.
  for v_post in select * from jsonb_array_elements(v_post_rows)
  loop
    insert into public.listing_conditions (
      id, listing_version_id, kind, metric, operator, text_threshold
    ) values (
      (v_post ->> 'id')::uuid,
      v_version_id,
      'post'::public.condition_kind,
      'post_must_mention'::public.condition_metric,
      'contains',
      v_post ->> 'text'
    );
  end loop;

  -- Sample videos: platform is classified by the edge function via
  -- classifyVideoUrl; the payload guarantees platform + url are both present.
  v_sort := 0;
  for v_sample in select * from jsonb_array_elements(v_sample_rows)
  loop
    insert into public.sample_videos (
      listing_version_id, platform, url, sort_order
    ) values (
      v_version_id,
      (v_sample ->> 'platform')::public.platform,
      v_sample ->> 'url',
      v_sort
    );
    v_sort := v_sort + 1;
  end loop;

  -- Close the circular FK. The trg_bump_listing_version trigger fires BEFORE
  -- UPDATE but versioned_changed is false here (no price/currency/max/cue
  -- change), so it passes through without inserting another listing_versions
  -- row. updated_at is refreshed so the ORDER BY created_at DESC on the feed
  -- still sees fresh listings.
  update public.listings
     set current_version_id = v_version_id,
         updated_at         = now()
   where id = v_listing_id;

  return jsonb_build_object(
    'listing_id', v_listing_id,
    'version_id', v_version_id
  );
end;
$$;

revoke all on function public.create_listing_rpc(uuid, jsonb) from public;
revoke all on function public.create_listing_rpc(uuid, jsonb) from anon, authenticated;
grant execute on function public.create_listing_rpc(uuid, jsonb) to service_role;

comment on function public.create_listing_rpc(uuid, jsonb) is
  'US-053 create-listing RPC. Atomic insert of listings + listing_versions + listing_conditions + sample_videos. Called only by the create-listing edge function via service_role.';

import { useCallback } from 'react';
import {
  KeyboardAvoidingView,
  Platform,
  Pressable,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';
import { router } from 'expo-router';
import { ChevronLeft, Trash2 } from 'lucide-react-native';
import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { textStyles } from '@/design/typography';
import { classifyVideoUrl } from '@/lib/oembed';
import { useWizard } from '@/screens/campaign-wizard/WizardStore';

// US-052 — Create-campaign wizard step 4 (sample videos + max submissions).
// Per-row URL validation reuses `classifyVideoUrl` from `src/lib/oembed.ts`
// so the wizard preview and the server-side submit path (US-046 / the
// submit-video edge function) agree on what counts as a TikTok or Instagram
// URL. Empty rows are allowed and will be filtered at publish (step-5) —
// Next stays enabled so users can still navigate while drafting, and step-5
// is the final gate before the listing is created.
//
// max_submissions maps 1:1 onto `listings.max_submissions` (integer nullable,
// docs/tech-architecture.md §4.7). Empty input = null = "no cap".

// Digits-only filter for the max-submissions field. 5-digit cap keeps real
// inputs well under int32 without needing an explicit range check.
const MAX_SUBMISSIONS_RE = /^\d*$/;
const MAX_SUBMISSIONS_DIGITS = 5;

export default function CampaignWizardStep4() {
  const { draft, updateField, setField } = useWizard();

  // Array mutations use the functional updater (Codebase Pattern #128) so
  // rapid-fire taps don't drop writes against a stale closure snapshot.
  const onAddRow = useCallback(() => {
    updateField('sampleUrls', (prev) => [...prev, '']);
  }, [updateField]);

  const onRemoveRow = useCallback(
    (index: number) => {
      updateField('sampleUrls', (prev) => prev.filter((_, i) => i !== index));
    },
    [updateField],
  );

  const onChangeUrl = useCallback(
    (index: number, next: string) => {
      updateField('sampleUrls', (prev) =>
        prev.map((u, i) => (i === index ? next : u)),
      );
    },
    [updateField],
  );

  const onChangeMax = useCallback(
    (next: string) => {
      if (next !== '' && !MAX_SUBMISSIONS_RE.test(next)) return;
      // `maxLength` on <TextInput> caps keyboard input but not pasted input,
      // so enforce the digit limit here too — otherwise a pasted "100000"
      // would land in the store even though the visible input stays capped.
      if (next.length > MAX_SUBMISSIONS_DIGITS) return;
      if (next === '') {
        setField('maxSubmissions', null);
        return;
      }
      const parsed = Number.parseInt(next, 10);
      setField('maxSubmissions', Number.isFinite(parsed) ? parsed : null);
    },
    [setField],
  );

  const onNext = useCallback(() => {
    router.push('/(lister)/campaigns/new/step-5');
  }, []);

  const onBack = useCallback(() => {
    if (router.canGoBack()) router.back();
    else router.replace('/(lister)/campaigns/new/step-3');
  }, []);

  const maxDisplay =
    draft.maxSubmissions === null ? '' : String(draft.maxSubmissions);

  return (
    <SafeAreaView style={styles.root}>
      <KeyboardAvoidingView
        style={styles.flex}
        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
      >
        <ScrollView
          contentContainerStyle={styles.scroll}
          keyboardShouldPersistTaps="handled"
        >
          <View style={styles.header}>
            <Pressable
              onPress={onBack}
              hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
              accessibilityRole="button"
              accessibilityLabel="Back"
              testID="wizard-step4-back"
              style={styles.backBtn}
            >
              <ChevronLeft size={24} color={colors.ink} />
            </Pressable>
            <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
              Step 4 of 5
            </Text>
            <Text style={[textStyles.display, styles.title]} maxFontSizeMultiplier={1.3}>
              Samples & limits
            </Text>
            <Text style={[textStyles.body, styles.subtitle]} maxFontSizeMultiplier={1.3}>
              Reference videos creators should match, and a cap on approved submissions.
            </Text>
          </View>

          <View style={styles.section}>
            <Text style={[textStyles.caption, styles.sectionLabel]} maxFontSizeMultiplier={1.3}>
              Sample videos
            </Text>
            <Text style={[textStyles.body, styles.sectionHint]} maxFontSizeMultiplier={1.3}>
              TikTok or Instagram URLs. Optional.
            </Text>

            <View style={styles.rows}>
              {draft.sampleUrls.map((url, index) => (
                // Using index as the key is safe here: rows aren't
                // re-orderable, and removing one dismounts the trash
                // button anyway (focus is never preserved across remove).
                <SampleRow
                  key={index}
                  url={url}
                  index={index}
                  onChange={onChangeUrl}
                  onRemove={onRemoveRow}
                />
              ))}
              {draft.sampleUrls.length === 0 ? (
                <Text style={[textStyles.body, styles.emptyHint]} maxFontSizeMultiplier={1.3}>
                  No samples yet. Add one below.
                </Text>
              ) : null}
              <ButtonSecondary
                label="Add sample"
                onPress={onAddRow}
                accessibilityLabel="Add sample video"
                testID="wizard-step4-add"
              />
            </View>
          </View>

          <View style={styles.section}>
            <Text style={[textStyles.caption, styles.sectionLabel]} maxFontSizeMultiplier={1.3}>
              Max submissions
            </Text>
            <Text style={[textStyles.body, styles.sectionHint]} maxFontSizeMultiplier={1.3}>
              How many creators can be approved. Leave empty for no cap.
            </Text>
            <View style={[styles.inputWrap, shadows.hard]}>
              <TextInput
                value={maxDisplay}
                onChangeText={onChangeMax}
                placeholder="No cap"
                placeholderTextColor={colors.ink40}
                keyboardType="number-pad"
                maxLength={MAX_SUBMISSIONS_DIGITS}
                style={[textStyles.body, styles.input]}
                accessibilityLabel="Max submissions"
                testID="wizard-step4-max"
              />
            </View>
          </View>

          <ButtonPrimary
            label="Next"
            onPress={onNext}
            accessibilityLabel="Go to wizard step 5"
            testID="wizard-step4-next"
          />
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

type SampleRowProps = {
  url: string;
  index: number;
  onChange: (index: number, next: string) => void;
  onRemove: (index: number) => void;
};

function SampleRow({ url, index, onChange, onRemove }: SampleRowProps) {
  const onUrlChange = useCallback(
    (next: string) => onChange(index, next),
    [onChange, index],
  );
  const onRemovePress = useCallback(() => onRemove(index), [onRemove, index]);

  const trimmed = url.trim();
  const classification = trimmed.length === 0 ? null : classifyVideoUrl(trimmed);
  const hasError = trimmed.length > 0 && classification === null;

  const platformLabel =
    classification?.platform === 'tiktok'
      ? 'TikTok'
      : classification?.platform === 'instagram'
        ? 'Instagram'
        : 'Sample';

  return (
    <View style={[styles.card, shadows.hard]} testID={`wizard-step4-row-${index}`}>
      <View style={styles.cardHeader}>
        <Text style={[textStyles.caption, styles.cardTitle]} maxFontSizeMultiplier={1.3}>
          {`${platformLabel} ${index + 1}`}
        </Text>
        <Pressable
          onPress={onRemovePress}
          hitSlop={{ top: 8, bottom: 8, left: 8, right: 8 }}
          accessibilityRole="button"
          accessibilityLabel={`Remove sample ${index + 1}`}
          testID={`wizard-step4-remove-${index}`}
        >
          <Trash2 size={18} color={colors.ink70} />
        </Pressable>
      </View>

      <View
        style={[
          styles.inputWrap,
          shadows.hard,
          hasError && styles.inputWrapError,
        ]}
      >
        <TextInput
          value={url}
          onChangeText={onUrlChange}
          placeholder="https://www.tiktok.com/@user/video/..."
          placeholderTextColor={colors.ink40}
          autoCapitalize="none"
          autoCorrect={false}
          keyboardType="url"
          style={[textStyles.body, styles.input]}
          accessibilityLabel={`Sample URL ${index + 1}`}
          testID={`wizard-step4-row-${index}-url`}
        />
      </View>

      {hasError ? (
        <Text
          style={[textStyles.caption, styles.errorText]}
          maxFontSizeMultiplier={1.3}
          testID={`wizard-step4-row-${index}-error`}
        >
          Must be a TikTok or Instagram video URL.
        </Text>
      ) : null}
    </View>
  );
}

const styles = StyleSheet.create({
  root: { flex: 1, backgroundColor: colors.canvas },
  flex: { flex: 1 },
  scroll: {
    padding: spacing.base,
    gap: spacing.xl,
    paddingBottom: spacing.xxxl,
  },
  header: {
    gap: spacing.xs,
    paddingTop: spacing.sm,
  },
  backBtn: {
    alignSelf: 'flex-start',
    padding: spacing.xs,
    marginLeft: -spacing.xs,
    marginBottom: spacing.xs,
  },
  stepLabel: {
    color: colors.ink70,
  },
  title: {
    color: colors.ink,
  },
  subtitle: {
    color: colors.ink70,
  },
  section: {
    gap: spacing.xs,
  },
  sectionLabel: {
    color: colors.ink,
  },
  sectionHint: {
    color: colors.ink70,
    marginBottom: spacing.xs,
  },
  rows: {
    gap: spacing.base,
  },
  emptyHint: {
    color: colors.ink70,
    textAlign: 'center',
    paddingVertical: spacing.md,
  },
  card: {
    backgroundColor: colors.surface,
    borderRadius: radii.card,
    borderWidth: 2,
    borderColor: colors.ink,
    padding: spacing.base,
    gap: spacing.md,
  },
  cardHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  cardTitle: {
    color: colors.ink,
  },
  inputWrap: {
    backgroundColor: colors.surface,
    borderRadius: radii.input,
    borderWidth: 2,
    borderColor: colors.ink,
  },
  inputWrapError: {
    borderColor: colors.danger,
  },
  input: {
    paddingHorizontal: spacing.base,
    paddingVertical: spacing.md,
    color: colors.ink,
    minHeight: 48,
  },
  errorText: {
    color: colors.danger,
  },
});

import { useCallback } from 'react';
import {
  KeyboardAvoidingView,
  Platform,
  Pressable,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';
import { router } from 'expo-router';
import { ChevronLeft, Trash2 } from 'lucide-react-native';
import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { textStyles } from '@/design/typography';
import {
  useWizard,
  type WizardPostCondition,
} from '@/screens/campaign-wizard/WizardStore';

// US-051 — Create-campaign wizard step 3 (post-conditions). Free-text rules the
// creator will self-affirm at submit time (docs/product-plan.md §3.1). Each row
// gets a stable RFC-4122 v4 UUID so the submission flow (US-045 / US-046) can
// map per-rule affirmations back to their source rule, and so the publish step
// can write them as `listing_conditions` rows with `condition_kind='post'`
// without a server-side re-mint.
//
// Rows are stored in the wizard draft (AsyncStorage-backed, see WizardStore).
// Post-conditions are optional — an empty list is a valid "no content rules"
// listing, matching step-2's posture for pre-conditions. Next is always enabled.

// Simple RFC-4122 v4 generator — Math.random is adequate for wizard-local ids
// (no security boundary; the server re-validates at publish). Avoids adding an
// `expo-crypto` dep just for this one call site.
function makeUuid(): string {
  const bytes = new Array<number>(16);
  for (let i = 0; i < 16; i++) bytes[i] = Math.floor(Math.random() * 256);
  bytes[6] = (bytes[6] & 0x0f) | 0x40;
  bytes[8] = (bytes[8] & 0x3f) | 0x80;
  const hex = bytes.map((b) => b.toString(16).padStart(2, '0')).join('');
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
}

export default function CampaignWizardStep3() {
  const { draft, updateField } = useWizard();

  // All mutations use `updateField`'s functional updater so rapid-fire taps
  // (Codebase Pattern #128) read the latest array rather than a stale closure.
  const onAddRow = useCallback(() => {
    const row: WizardPostCondition = { id: makeUuid(), text: '' };
    updateField('postConditions', (prev) => [...prev, row]);
  }, [updateField]);

  const onRemoveRow = useCallback(
    (id: string) => {
      updateField('postConditions', (prev) => prev.filter((row) => row.id !== id));
    },
    [updateField],
  );

  const onChangeText = useCallback(
    (id: string, text: string) => {
      updateField('postConditions', (prev) =>
        prev.map((row) => (row.id === id ? { ...row, text } : row)),
      );
    },
    [updateField],
  );

  const onNext = useCallback(() => {
    router.push('/(lister)/campaigns/new/step-4');
  }, []);

  const onBack = useCallback(() => {
    if (router.canGoBack()) router.back();
    else router.replace('/(lister)/campaigns/new/step-2');
  }, []);

  return (
    <SafeAreaView style={styles.root}>
      <KeyboardAvoidingView
        style={styles.flex}
        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
      >
        <ScrollView
          contentContainerStyle={styles.scroll}
          keyboardShouldPersistTaps="handled"
        >
          <View style={styles.header}>
            <Pressable
              onPress={onBack}
              hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
              accessibilityRole="button"
              accessibilityLabel="Back"
              testID="wizard-step3-back"
              style={styles.backBtn}
            >
              <ChevronLeft size={24} color={colors.ink} />
            </Pressable>
            <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
              Step 3 of 5
            </Text>
            <Text style={[textStyles.display, styles.title]} maxFontSizeMultiplier={1.3}>
              Content rules
            </Text>
            <Text style={[textStyles.body, styles.subtitle]} maxFontSizeMultiplier={1.3}>
              Rules creators must self-affirm before submitting. Leave empty to set no rules.
            </Text>
          </View>

          <View style={styles.rows}>
            {draft.postConditions.map((row, index) => (
              <PostConditionCard
                key={row.id}
                row={row}
                index={index}
                onChangeText={onChangeText}
                onRemove={onRemoveRow}
              />
            ))}
            {draft.postConditions.length === 0 ? (
              <Text style={[textStyles.body, styles.emptyHint]} maxFontSizeMultiplier={1.3}>
                No rules yet. Add one below.
              </Text>
            ) : null}
            <ButtonSecondary
              label="Add rule"
              onPress={onAddRow}
              accessibilityLabel="Add post-condition"
              testID="wizard-step3-add"
            />
          </View>

          <ButtonPrimary
            label="Next"
            onPress={onNext}
            accessibilityLabel="Go to wizard step 4"
            testID="wizard-step3-next"
          />
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

type PostConditionCardProps = {
  row: WizardPostCondition;
  index: number;
  onChangeText: (id: string, text: string) => void;
  onRemove: (id: string) => void;
};

function PostConditionCard({ row, index, onChangeText, onRemove }: PostConditionCardProps) {
  const onTextChange = useCallback(
    (next: string) => onChangeText(row.id, next),
    [onChangeText, row.id],
  );
  const onRemovePress = useCallback(() => onRemove(row.id), [onRemove, row.id]);

  return (
    <View style={[styles.card, shadows.hard]} testID={`wizard-step3-row-${index}`}>
      <View style={styles.cardHeader}>
        <Text style={[textStyles.caption, styles.cardTitle]} maxFontSizeMultiplier={1.3}>
          Rule {index + 1}
        </Text>
        <Pressable
          onPress={onRemovePress}
          hitSlop={{ top: 8, bottom: 8, left: 8, right: 8 }}
          accessibilityRole="button"
          accessibilityLabel={`Remove rule ${index + 1}`}
          testID={`wizard-step3-remove-${index}`}
        >
          <Trash2 size={18} color={colors.ink70} />
        </Pressable>
      </View>

      <View style={[styles.inputWrap, shadows.hard]}>
        <TextInput
          value={row.text}
          onChangeText={onTextChange}
          placeholder="e.g. Mentions the brand in the first 10 seconds"
          placeholderTextColor={colors.ink40}
          multiline
          autoCapitalize="sentences"
          maxFontSizeMultiplier={1.3}
          style={[textStyles.body, styles.input]}
          accessibilityLabel={`Rule ${index + 1} text`}
          testID={`wizard-step3-row-${index}-text`}
        />
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  root: { flex: 1, backgroundColor: colors.canvas },
  flex: { flex: 1 },
  scroll: {
