1	// Edge function: apply-to-listing (US-041)
2	//
3	// Contract:
4	//   POST { listing_id: string, cover_note?: string }
5	//     → 200 { application_id: string, listing_version_id: string }
6	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
7	//     → 401 { error: 'UNAUTHORIZED' }
8	//     → 403 { error: 'FORBIDDEN' }                      // non-creator role
9	//     → 403 { error: 'INELIGIBLE',
10	//             failed_conditions: Array<{metric, platform, required, actual}> }
11	//     → 404 { error: 'LISTING_NOT_FOUND' }              // also covers draft/archived
12	//     → 409 { error: 'LISTING_NOT_ACTIVE' }
13	//     → 409 { error: 'LISTING_VERSION_CHANGED',
14	//             current_version_id: string }
15	//     → 409 { error: 'ALREADY_APPLIED' }
16	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
17	//
18	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
19	//       _shared/jwt.ts and asserts role='creator'. Deployed with
20	//       verify_jwt=false at the gateway because the gateway only knows
21	//       about Supabase's own JWT secret — the handler enforces auth.
22	//
23	// Request shape — canonical per docs/tech-architecture.md §5.5
24	// (Req: `{ listing_id, cover_note? }`). The US-041 story AC names the
25	// optional field `pitch`; the spec name `cover_note` wins per the Ralph
26	// iteration rules and also matches the `public.applications.cover_note`
27	// column.
28	//
29	// Concurrency — we re-run eligibility in TS against the current version
30	// of the listing, then hand the same `expected_version_id` to the
31	// `public.apply_to_listing_rpc` RPC, which re-reads the listing under a
32	// row-level lock (SELECT ... FOR UPDATE). If the lister's version bump
33	// interleaves, the RPC sees a different current_version_id and returns
34	// LISTING_VERSION_CHANGED. This satisfies the §5.5 "re-run eligibility
35	// against the NOW-current version_id" invariant without duplicating the
36	// eligibility engine in PL/pgSQL. Spec §5.5 also enumerates
37	// LISTING_NOT_ACTIVE and ALREADY_APPLIED, both surfaced here.
38	//
39	// Fail-closed on missing metrics — inherited from the shared eligibility
40	// engine (docs/tech-architecture.md §3d): missing creator_profiles row,
41	// null platform fields, or unknown operators on a PRE condition all
42	// count as ineligible.
43	
44	import { createClient } from "npm:@supabase/supabase-js@2";
45	import { verifyJwt } from "../_shared/jwt.ts";
46	import { corsHeaders } from "../_shared/cors.ts";
47	import {
48	  type ConditionRow,
49	  type CreatorProfileRow,
50	  EMPTY_CREATOR_METRICS,
51	  evaluatePreConditions,
52	} from "../_shared/eligibility.ts";
53	
54	const UUID_RE =
55	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
56	
57	// Hard cap on cover_note — the schema column is `text` (unlimited), but
58	// anything longer than a few paragraphs is almost certainly abuse or
59	// accidental paste. 2000 chars = roughly 400 words, plenty for a pitch.
60	const COVER_NOTE_MAX_LEN = 2000;
61	
62	interface ApplyRequest {
63	  listing_id?: unknown;
64	  cover_note?: unknown;
65	}
66	
67	function jsonResponse(status: number, body: unknown): Response {
68	  return new Response(JSON.stringify(body), {
69	    status,
70	    headers: { ...corsHeaders, "Content-Type": "application/json" },
71	  });
72	}
73	
74	function bearerToken(req: Request): string | null {
75	  const raw = req.headers.get("Authorization") ??
76	    req.headers.get("authorization");
77	  if (!raw) return null;
78	  const m = raw.match(/^Bearer\s+(.+)$/i);
79	  return m ? m[1].trim() : null;
80	}
81	
82	Deno.serve(async (req) => {
83	  if (req.method === "OPTIONS") {
84	    return new Response(null, { status: 204, headers: corsHeaders });
85	  }
86	  if (req.method !== "POST") {
87	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
88	  }
89	
90	  const token = bearerToken(req);
91	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
92	
93	  let claims;
94	  try {
95	    claims = await verifyJwt(token);
96	  } catch {
97	    return jsonResponse(401, { error: "UNAUTHORIZED" });
98	  }
99	  if (claims.app_role !== "creator") {
100	    return jsonResponse(403, { error: "FORBIDDEN" });
101	  }
102	
103	  let body: ApplyRequest;
104	  try {
