13	//       threshold: number (integer, >= 0),
14	//     }>,
15	//     post_conditions: Array<{ id: string (uuid), text: string (1..500 trim) }>,
16	//     sample_urls:     Array<string>  // each must classify as tiktok|instagram
17	//   }
18	//     → 201 { listing_id: string, version_id: string }
19	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST', field?: string }
20	//     → 401 { error: 'UNAUTHORIZED' }
21	//     → 403 { error: 'FORBIDDEN' }                 // non-lister role
22	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
