40	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
41	
42	const TITLE_MIN = 1;
43	const TITLE_MAX = 200;
44	const DESCRIPTION_MIN = 1;
45	const DESCRIPTION_MAX = 5000;
