86	  price_cents: number;
87	  currency: string;
88	  max_submissions: number | null;
89	  pre_conditions: Array<{
90	    platform: "tiktok" | "instagram";
91	    metric: "followers" | "avg_views";
92	    threshold: number;
93	  }>;
94	  post_conditions: Array<{ id: string; text: string }>;
95	  sample_videos: Array<{ platform: "tiktok" | "instagram"; url: string }>;
96	}
