98	function jsonResponse(status: number, body: unknown): Response {
99	  return new Response(JSON.stringify(body), {
100	    status,
101	    headers: { ...corsHeaders, "Content-Type": "application/json" },
102	  });
103	}
104	
105	function bearerToken(req: Request): string | null {
106	  const raw = req.headers.get("Authorization") ??
107	    req.headers.get("authorization");
108	  if (!raw) return null;
109	  const m = raw.match(/^Bearer\s+(.+)$/i);
110	  return m ? m[1].trim() : null;
111	}
112	
113	function isNonNegativeSafeInt(n: unknown, max: number): n is number {
114	  return typeof n === "number" && Number.isFinite(n) && Number.isInteger(n) &&
115	    n >= 0 && n <= max;
116	}
117	
118	function validate(body: RawRequest):
119	  | { ok: true; payload: NormalizedPayload }
120	  | { ok: false; field: string } {
121	  if (typeof body.title !== "string") return { ok: false, field: "title" };
122	  const title = body.title.trim();
123	  if (title.length < TITLE_MIN || title.length > TITLE_MAX) {
124	    return { ok: false, field: "title" };
125	  }
126	
127	  if (typeof body.description !== "string") {
128	    return { ok: false, field: "description" };
129	  }
130	  const description = body.description.trim();
131	  if (
132	    description.length < DESCRIPTION_MIN ||
133	    description.length > DESCRIPTION_MAX
134	  ) {
135	    return { ok: false, field: "description" };
136	  }
