149	  if (body.max_submissions !== null && body.max_submissions !== undefined) {
150	    if (
151	      typeof body.max_submissions !== "number" ||
152	      !Number.isInteger(body.max_submissions) ||
153	      body.max_submissions < 1 ||
154	      body.max_submissions > MAX_SUBMISSIONS_MAX
155	    ) {
156	      return { ok: false, field: "max_submissions" };
157	    }
158	    maxSubmissions = body.max_submissions;
159	  }
160	
161	  if (!Array.isArray(body.pre_conditions)) {
162	    return { ok: false, field: "pre_conditions" };
163	  }
164	  if (body.pre_conditions.length > PRE_CONDITIONS_MAX) {
165	    return { ok: false, field: "pre_conditions" };
166	  }
167	  const preConditions: NormalizedPayload["pre_conditions"] = [];
168	  for (const rawRow of body.pre_conditions) {
169	    const row = rawRow as RawPreCondition;
170	    if (typeof row !== "object" || row === null) {
171	      return { ok: false, field: "pre_conditions" };
172	    }
173	    if (typeof row.platform !== "string" || !ALLOWED_PRE_PLATFORMS.has(row.platform)) {
174	      return { ok: false, field: "pre_conditions.platform" };
175	    }
176	    if (typeof row.metric !== "string" || !ALLOWED_PRE_METRICS.has(row.metric)) {
177	      return { ok: false, field: "pre_conditions.metric" };
178	    }
179	    if (!isNonNegativeSafeInt(row.threshold, PRE_THRESHOLD_MAX)) {
180	      return { ok: false, field: "pre_conditions.threshold" };
181	    }
182	    preConditions.push({
183	      platform: row.platform as "tiktok" | "instagram",
184	      metric: row.metric as "followers" | "avg_views",
185	      threshold: row.threshold,
186	    });
187	  }
188	
189	  if (!Array.isArray(body.post_conditions)) {
190	    return { ok: false, field: "post_conditions" };
191	  }
192	  if (body.post_conditions.length > POST_CONDITIONS_MAX) {
193	    return { ok: false, field: "post_conditions" };
194	  }
195	  const postConditions: NormalizedPayload["post_conditions"] = [];
196	  const seenPostIds = new Set<string>();
197	  for (const rawRow of body.post_conditions) {
198	    const row = rawRow as RawPostCondition;
199	    if (typeof row !== "object" || row === null) {
200	      return { ok: false, field: "post_conditions" };
201	    }
202	    if (typeof row.id !== "string" || !UUID_RE.test(row.id)) {
203	      return { ok: false, field: "post_conditions.id" };
204	    }
205	    if (seenPostIds.has(row.id)) {
206	      return { ok: false, field: "post_conditions.id" };
207	    }
208	    seenPostIds.add(row.id);
209	    if (typeof row.text !== "string") {
210	      return { ok: false, field: "post_conditions.text" };
211	    }
212	    const text = row.text.trim();
