241	  return {
242	    ok: true,
243	    payload: {
244	      title,
245	      description,
246	      price_cents: priceCents,
247	      currency,
248	      max_submissions: maxSubmissions,
249	      pre_conditions: preConditions,
250	      post_conditions: postConditions,
251	      sample_videos: sampleVideos,
252	    },
253	  };
254	}
