256	Deno.serve(async (req) => {
257	  if (req.method === "OPTIONS") {
258	    return new Response(null, { status: 204, headers: corsHeaders });
259	  }
260	  if (req.method !== "POST") {
261	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
262	  }
263	
264	  const token = bearerToken(req);
265	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
266	
267	  let claims;
268	  try {
269	    claims = await verifyJwt(token);
270	  } catch {
271	    return jsonResponse(401, { error: "UNAUTHORIZED" });
272	  }
273	  if (claims.app_role !== "lister") {
274	    return jsonResponse(403, { error: "FORBIDDEN" });
275	  }
276	
277	  let raw: RawRequest;
278	  try {
279	    raw = await req.json();
280	  } catch {
281	    return jsonResponse(400, { error: "INVALID_JSON" });
282	  }
283	
284	  const result = validate(raw);
285	  if (!result.ok) {
286	    return jsonResponse(400, { error: "INVALID_REQUEST", field: result.field });
287	  }
288	
289	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
290	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
291	  if (!supabaseUrl || !serviceRoleKey) {
292	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
293	  }
294	
295	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
296	    auth: { persistSession: false, autoRefreshToken: false },
297	  });
298	
299	  const { data: rpcData, error: rpcError } = await supabase.rpc(
300	    "create_listing_rpc",
301	    {
302	      p_lister_id: claims.sub,
303	      p_payload: result.payload as unknown as Record<string, unknown>,
304	    },
305	  );
306	
307	  if (rpcError) {
308	    console.error("create_listing_rpc error", rpcError);
309	    return jsonResponse(500, { error: "DB_ERROR" });
310	  }
311	
312	  const shaped = rpcData as
313	    | { listing_id?: string; version_id?: string }
314	    | null;
315	  if (!shaped?.listing_id || !shaped.version_id) {
316	    console.error("create_listing_rpc returned unexpected shape", rpcData);
317	    return jsonResponse(500, { error: "DB_ERROR" });
318	  }
319	
320	  return jsonResponse(201, {
321	    listing_id: shaped.listing_id,
322	    version_id: shaped.version_id,
323	  });
324	});
