2	//
3	// Consumers: submit-video (US-045). Extend here before adding platforms.
4	//
5	// Platform detection is based on URL host + path shape — we accept the
6	// common formats a creator is likely to paste:
7	//   TikTok:    https://www.tiktok.com/@handle/video/1234567890
8	//              https://vm.tiktok.com/XXXXXXX/      (share redirect)
9	//              https://vt.tiktok.com/XXXXXXX/      (share redirect)
10	//              https://www.tiktok.com/t/XXXXXXX/   (share redirect)
11	//   Instagram: https://www.instagram.com/p/<code>/
12	//              https://www.instagram.com/reel/<code>/
13	//              https://www.instagram.com/tv/<code>/
14	//
15	// external_id extraction is best-effort. For canonical TikTok URLs the
16	// trailing numeric video id is the external_id; for shortlinks we leave
17	// external_id null and let the oEmbed response (if available) provide it
18	// via provider-specific fields (currently unused). The
19	// `submission_reuse_view` in public skips rows with external_id IS NULL,
20	// so shortlink-only rows simply don't participate in reuse counting until
21	// the lister paste-flow hands us a canonical URL.
22	//
23	// oEmbed endpoints (docs/tech-architecture.md §3h):
24	//   TikTok:    GET https://www.tiktok.com/oembed?url=<share_url>      (no auth)
25	//   Instagram: GET https://graph.facebook.com/v<ver>/instagram_oembed (app-token)
26	//
27	// Instagram oEmbed requires an app-level Meta token. We do NOT have one
28	// configured, so IG validation here is regex-shape only; the spec §3h
29	// notes this requirement. Expand `fetchOembed` once the token is wired.
30	
31	export type OembedPlatform = "tiktok" | "instagram";
32	
33	export interface UrlClassification {
34	  platform: OembedPlatform;
35	  externalId: string | null;
36	}
37	
38	export interface OembedResult {
39	  thumbnailUrl: string | null;
40	  authorHandle: string | null;
41	  raw: Record<string, unknown>;
42	}
43	
44	const TIKTOK_CANONICAL_RE =
45	  /^https:\/\/(?:www\.)?tiktok\.com\/@[A-Za-z0-9._-]+\/video\/(\d+)/i;
46	const TIKTOK_SHORTLINK_RE =
47	  /^https:\/\/(?:vm|vt)\.tiktok\.com\/[A-Za-z0-9]+\/?/i;
48	const TIKTOK_TLINK_RE =
49	  /^https:\/\/(?:www\.)?tiktok\.com\/t\/[A-Za-z0-9]+\/?/i;
50	
51	const INSTAGRAM_RE =
52	  /^https:\/\/(?:www\.)?instagram\.com\/(?:p|reel|tv)\/([A-Za-z0-9_-]+)\/?/i;
53	
54	export function classifyVideoUrl(url: string): UrlClassification | null {
55	  if (typeof url !== "string") return null;
56	  const trimmed = url.trim();
57	  if (trimmed.length === 0) return null;
58	
59	  const canon = trimmed.match(TIKTOK_CANONICAL_RE);
60	  if (canon) {
61	    return { platform: "tiktok", externalId: canon[1] };
62	  }
63	  if (TIKTOK_SHORTLINK_RE.test(trimmed) || TIKTOK_TLINK_RE.test(trimmed)) {
64	    return { platform: "tiktok", externalId: null };
65	  }
66	  const ig = trimmed.match(INSTAGRAM_RE);
67	  if (ig) {
68	    return { platform: "instagram", externalId: ig[1] };
69	  }
70	  return null;
71	}
72	
73	export async function fetchTikTokOembed(
74	  url: string,
75	): Promise<OembedResult | null> {
76	  const endpoint = `https://www.tiktok.com/oembed?url=${encodeURIComponent(url)}`;
77	  let response: Response;
78	  try {
79	    response = await fetch(endpoint, {
80	      headers: { "User-Agent": "marketify-submit-video/1.0" },
81	    });
82	  } catch (_err) {
83	    // Network failures are treated as "URL could not be validated" at the
84	    // caller's discretion. Throw fixed-string errors rather than ${err}
85	    // to avoid leaking internal paths if fetch implementations ever grow
86	    // diagnostic info.
87	    throw new Error("TikTok oEmbed fetch failed");
88	  }
89	  if (response.status === 404 || response.status === 400) {
90	    return null;
91	  }
92	  if (!response.ok) {
93	    throw new Error(`TikTok oEmbed HTTP ${response.status}`);
94	  }
95	  let data: Record<string, unknown>;
96	  try {
97	    data = await response.json();
98	  } catch {
99	    throw new Error("TikTok oEmbed returned non-JSON");
100	  }
101	  const thumbnailUrl = typeof data.thumbnail_url === "string"
102	    ? data.thumbnail_url
103	    : null;
104	  const authorHandle = extractTikTokAuthorHandle(data);
105	  return { thumbnailUrl, authorHandle, raw: data };
106	}
107	
108	function extractTikTokAuthorHandle(
109	  data: Record<string, unknown>,
110	): string | null {
111	  // TikTok's oEmbed returns `author_unique_id` (canonical handle) and
112	  // `author_name` (display name). Prefer the unique id; strip any leading
113	  // @ because our social_links.handle is stored without it.
114	  const candidates = [data.author_unique_id, data.author_name];
115	  for (const raw of candidates) {
116	    if (typeof raw === "string") {
117	      const h = raw.trim().replace(/^@+/, "");
118	      if (h.length > 0) return h;
119	    }
120	  }
121	  return null;
122	}
