// Edge function: create-listing (US-053)
//
// Contract:
//   POST {
//     title:           string (1..200 after trim),
//     description:     string (1..5000 after trim),
//     price_cents:     number (integer, >= 0, <= 1e9),
//     currency:        'USD' | 'EUR' | 'GBP',
//     max_submissions: number | null (integer, 1..99999),
//     pre_conditions: Array<{
//       platform: 'tiktok' | 'instagram',
//       metric:   'followers' | 'avg_views',
//       threshold: number (integer, >= 0),
//     }>,
//     post_conditions: Array<{ id: string (uuid), text: string (1..500 trim) }>,
//     sample_urls:     Array<string>  // each must classify as tiktok|instagram
//   }
//     → 201 { listing_id: string, version_id: string }
//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST', field?: string }
//     → 401 { error: 'UNAUTHORIZED' }
//     → 403 { error: 'FORBIDDEN' }                 // non-lister role
//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
//
// Auth: Marketify HS256 JWT (MARKETIFY_JWT_SECRET), app_role must be 'lister'.
//       Gateway `verify_jwt` is disabled because Supabase-issued JWTs aren't
//       the same namespace — the handler enforces auth via _shared/jwt.ts.
//
// The handler is the validation boundary: the RPC assumes caller has already
// normalized shape. We classify sample URLs here (via _shared/oembed.ts) so
// the DB sees the same platform label the wizard preview showed the user.
// Empty / whitespace-only URL rows are dropped silently (the wizard allows
// blank rows as drafting state per US-052).

import { createClient } from "npm:@supabase/supabase-js@2";
import { verifyJwt } from "../_shared/jwt.ts";
import { corsHeaders } from "../_shared/cors.ts";
import { classifyVideoUrl } from "../_shared/oembed.ts";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

const TITLE_MIN = 1;
const TITLE_MAX = 200;
const DESCRIPTION_MIN = 1;
const DESCRIPTION_MAX = 5000;
const PRICE_CENTS_MAX = 1_000_000_000;
const MAX_SUBMISSIONS_MAX = 99_999;
const POST_TEXT_MAX = 500;
const PRE_CONDITIONS_MAX = 10;
const POST_CONDITIONS_MAX = 20;
const SAMPLE_URLS_MAX = 10;
// Cap pre-condition thresholds at PG int32 max — the RPC casts threshold to
// `::integer` when populating the min_followers_* cache columns, so a value
// above 2,147,483,647 would blow up inside the transaction as a DB_ERROR
// instead of the 400 INVALID_REQUEST the caller actually deserves.
const PRE_THRESHOLD_MAX = 2_147_483_647;
const ALLOWED_CURRENCIES = new Set(["USD", "EUR", "GBP"]);
const ALLOWED_PRE_PLATFORMS = new Set(["tiktok", "instagram"]);
const ALLOWED_PRE_METRICS = new Set(["followers", "avg_views"]);

interface RawRequest {
  title?: unknown;
  description?: unknown;
  price_cents?: unknown;
  currency?: unknown;
  max_submissions?: unknown;
  pre_conditions?: unknown;
  post_conditions?: unknown;
  sample_urls?: unknown;
}

interface RawPreCondition {
  platform?: unknown;
  metric?: unknown;
  threshold?: unknown;
}

interface RawPostCondition {
  id?: unknown;
  text?: unknown;
}

interface NormalizedPayload {
  title: string;
  description: string;
  price_cents: number;
  currency: string;
  max_submissions: number | null;
  pre_conditions: Array<{
    platform: "tiktok" | "instagram";
    metric: "followers" | "avg_views";
    threshold: number;
  }>;
  post_conditions: Array<{ id: string; text: string }>;
  sample_videos: Array<{ platform: "tiktok" | "instagram"; url: string }>;
}

function jsonResponse(status: number, body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

function bearerToken(req: Request): string | null {
  const raw = req.headers.get("Authorization") ??
    req.headers.get("authorization");
  if (!raw) return null;
  const m = raw.match(/^Bearer\s+(.+)$/i);
  return m ? m[1].trim() : null;
}

function isNonNegativeSafeInt(n: unknown, max: number): n is number {
  return typeof n === "number" && Number.isFinite(n) && Number.isInteger(n) &&
    n >= 0 && n <= max;
}

function validate(body: RawRequest):
  | { ok: true; payload: NormalizedPayload }
  | { ok: false; field: string } {
  if (typeof body.title !== "string") return { ok: false, field: "title" };
  const title = body.title.trim();
  if (title.length < TITLE_MIN || title.length > TITLE_MAX) {
    return { ok: false, field: "title" };
  }

  if (typeof body.description !== "string") {
    return { ok: false, field: "description" };
  }
  const description = body.description.trim();
  if (
    description.length < DESCRIPTION_MIN ||
    description.length > DESCRIPTION_MAX
  ) {
    return { ok: false, field: "description" };
  }

  if (!isNonNegativeSafeInt(body.price_cents, PRICE_CENTS_MAX)) {
    return { ok: false, field: "price_cents" };
  }
  const priceCents = body.price_cents;

  if (typeof body.currency !== "string" || !ALLOWED_CURRENCIES.has(body.currency)) {
    return { ok: false, field: "currency" };
  }
  const currency = body.currency;

  let maxSubmissions: number | null = null;
  if (body.max_submissions !== null && body.max_submissions !== undefined) {
    if (
      typeof body.max_submissions !== "number" ||
      !Number.isInteger(body.max_submissions) ||
      body.max_submissions < 1 ||
      body.max_submissions > MAX_SUBMISSIONS_MAX
    ) {
      return { ok: false, field: "max_submissions" };
    }
    maxSubmissions = body.max_submissions;
  }

  if (!Array.isArray(body.pre_conditions)) {
    return { ok: false, field: "pre_conditions" };
  }
  if (body.pre_conditions.length > PRE_CONDITIONS_MAX) {
    return { ok: false, field: "pre_conditions" };
  }
  const preConditions: NormalizedPayload["pre_conditions"] = [];
  for (const rawRow of body.pre_conditions) {
    const row = rawRow as RawPreCondition;
    if (typeof row !== "object" || row === null) {
      return { ok: false, field: "pre_conditions" };
    }
    if (typeof row.platform !== "string" || !ALLOWED_PRE_PLATFORMS.has(row.platform)) {
      return { ok: false, field: "pre_conditions.platform" };
    }
    if (typeof row.metric !== "string" || !ALLOWED_PRE_METRICS.has(row.metric)) {
      return { ok: false, field: "pre_conditions.metric" };
    }
    if (!isNonNegativeSafeInt(row.threshold, PRE_THRESHOLD_MAX)) {
      return { ok: false, field: "pre_conditions.threshold" };
    }
    preConditions.push({
      platform: row.platform as "tiktok" | "instagram",
      metric: row.metric as "followers" | "avg_views",
      threshold: row.threshold,
    });
  }

  if (!Array.isArray(body.post_conditions)) {
    return { ok: false, field: "post_conditions" };
  }
  if (body.post_conditions.length > POST_CONDITIONS_MAX) {
    return { ok: false, field: "post_conditions" };
  }
  const postConditions: NormalizedPayload["post_conditions"] = [];
  const seenPostIds = new Set<string>();
  for (const rawRow of body.post_conditions) {
    const row = rawRow as RawPostCondition;
    if (typeof row !== "object" || row === null) {
      return { ok: false, field: "post_conditions" };
    }
    if (typeof row.id !== "string" || !UUID_RE.test(row.id)) {
      return { ok: false, field: "post_conditions.id" };
    }
    if (seenPostIds.has(row.id)) {
      return { ok: false, field: "post_conditions.id" };
    }
    seenPostIds.add(row.id);
    if (typeof row.text !== "string") {
      return { ok: false, field: "post_conditions.text" };
    }
    const text = row.text.trim();
    if (text.length === 0 || text.length > POST_TEXT_MAX) {
      return { ok: false, field: "post_conditions.text" };
    }
    postConditions.push({ id: row.id, text });
  }

  if (!Array.isArray(body.sample_urls)) {
    return { ok: false, field: "sample_urls" };
  }
  if (body.sample_urls.length > SAMPLE_URLS_MAX) {
    return { ok: false, field: "sample_urls" };
  }
  const sampleVideos: NormalizedPayload["sample_videos"] = [];
  for (const rawUrl of body.sample_urls) {
    if (typeof rawUrl !== "string") {
      return { ok: false, field: "sample_urls" };
    }
    const trimmed = rawUrl.trim();
    // Empty rows are wizard drafting state — drop silently so the user
    // doesn't need to explicitly remove them before tapping Publish.
    if (trimmed.length === 0) continue;
    const classification = classifyVideoUrl(trimmed);
    if (!classification) {
      return { ok: false, field: "sample_urls" };
    }
    sampleVideos.push({ platform: classification.platform, url: trimmed });
  }

  return {
    ok: true,
    payload: {
      title,
      description,
      price_cents: priceCents,
      currency,
      max_submissions: maxSubmissions,
      pre_conditions: preConditions,
      post_conditions: postConditions,
      sample_videos: sampleVideos,
    },
  };
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  const token = bearerToken(req);
  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });

  let claims;
  try {
    claims = await verifyJwt(token);
  } catch {
    return jsonResponse(401, { error: "UNAUTHORIZED" });
  }
  if (claims.app_role !== "lister") {
    return jsonResponse(403, { error: "FORBIDDEN" });
  }

  let raw: RawRequest;
  try {
    raw = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  const result = validate(raw);
  if (!result.ok) {
    return jsonResponse(400, { error: "INVALID_REQUEST", field: result.field });
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }

  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  const { data: rpcData, error: rpcError } = await supabase.rpc(
    "create_listing_rpc",
    {
      p_lister_id: claims.sub,
      p_payload: result.payload as unknown as Record<string, unknown>,
    },
  );

  if (rpcError) {
    console.error("create_listing_rpc error", rpcError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const shaped = rpcData as
    | { listing_id?: string; version_id?: string }
    | null;
  if (!shaped?.listing_id || !shaped.version_id) {
    console.error("create_listing_rpc returned unexpected shape", rpcData);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  return jsonResponse(201, {
    listing_id: shaped.listing_id,
    version_id: shaped.version_id,
  });
});

// Custom JWT helper for Marketify edge functions.
//
// Contract: signJwt({ sub, app_role, session_id }, { ttlSeconds? }) -> compact JWT.
//           verifyJwt(token) -> parsed claims or throws.
// Algorithm: HS256 (HMAC-SHA256) via Web Crypto.
// Secret: MARKETIFY_JWT_SECRET env var. Must match the Supabase project's
//         PostgREST jwt_secret so RLS sees the token as valid.
// Claims: `role` is the Postgres role PostgREST switches into ("authenticated"
//         for all logged-in users). The app-level role (creator | lister) lives
//         in `app_role` so it doesn't collide with PostgREST's role-switching
//         behavior. RLS policies read `sub` and `app_role` via `auth.jwt()`.
//         `session_id` feeds the denylist lookup in §15c.
// Auth:   no inbound auth requirement — this module is a building block.

export type AppRole = "creator" | "lister";

export interface JwtClaims {
  sub: string;
  role: "authenticated";
  app_role: AppRole;
  session_id: string;
  iat: number;
  exp: number;
}

export interface SignInput {
  sub: string;
  app_role: AppRole;
  session_id: string;
}

export interface SignOptions {
  ttlSeconds?: number;
}

const DEFAULT_TTL_SECONDS = 7 * 24 * 60 * 60;
const encoder = new TextEncoder();
const decoder = new TextDecoder();

function readSecret(): string {
  const s = Deno.env.get("MARKETIFY_JWT_SECRET");
  if (!s) throw new Error("MARKETIFY_JWT_SECRET is not set");
  return s;
}

function base64UrlEncode(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += String.fromCharCode(b);
  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
}

function base64UrlDecode(input: string): Uint8Array {
  const rem = input.length % 4;
  const b64 = (rem === 0 ? input : input + "=".repeat(4 - rem))
    .replaceAll("-", "+")
    .replaceAll("_", "/");
  let raw: string;
  try {
    raw = atob(b64);
  } catch {
    throw new Error("Malformed JWT");
  }
  const out = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
  return out;
}

async function importKey(
  secret: string,
  usages: KeyUsage[],
): Promise<CryptoKey> {
  return await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    usages,
  );
}

export async function signJwt(
  input: SignInput,
  options: SignOptions = {},
): Promise<string> {
  const ttl = options.ttlSeconds ?? DEFAULT_TTL_SECONDS;
  if (!Number.isFinite(ttl) || ttl <= 0) {
    throw new Error("ttlSeconds must be a positive finite number");
  }
  if (input.app_role !== "creator" && input.app_role !== "lister") {
    throw new Error("app_role must be 'creator' or 'lister'");
  }

  const now = Math.floor(Date.now() / 1000);
  const payload: JwtClaims = {
    sub: input.sub,
    role: "authenticated",
    app_role: input.app_role,
    session_id: input.session_id,
    iat: now,
    exp: now + ttl,
  };

  const headerB64 = base64UrlEncode(
    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
  );
  const payloadB64 = base64UrlEncode(encoder.encode(JSON.stringify(payload)));
  const signingInput = `${headerB64}.${payloadB64}`;

  const key = await importKey(readSecret(), ["sign"]);
  const sig = await crypto.subtle.sign(
    "HMAC",
    key,
    encoder.encode(signingInput),
  );
  const sigB64 = base64UrlEncode(new Uint8Array(sig));

  return `${signingInput}.${sigB64}`;
}

export async function verifyJwt(token: string): Promise<JwtClaims> {
  const parts = token.split(".");
  if (parts.length !== 3) throw new Error("Malformed JWT");
  const [headerB64, payloadB64, sigB64] = parts;

  let header: { alg?: string };
  try {
    header = JSON.parse(decoder.decode(base64UrlDecode(headerB64)));
  } catch {
    throw new Error("Malformed JWT");
  }
  if (header.alg !== "HS256") throw new Error("Unsupported JWT algorithm");

  const key = await importKey(readSecret(), ["verify"]);
  const ok = await crypto.subtle.verify(
    "HMAC",
    key,
    base64UrlDecode(sigB64),
    encoder.encode(`${headerB64}.${payloadB64}`),
  );
  if (!ok) throw new Error("Bad signature");

  let payload: Partial<JwtClaims>;
  try {
    payload = JSON.parse(decoder.decode(base64UrlDecode(payloadB64)));
  } catch {
    throw new Error("Malformed JWT");
  }

  if (
    typeof payload.sub !== "string" || payload.sub.length === 0 ||
    payload.role !== "authenticated" ||
    (payload.app_role !== "creator" && payload.app_role !== "lister") ||
    typeof payload.session_id !== "string" ||
    payload.session_id.length === 0 ||
    typeof payload.iat !== "number" ||
    typeof payload.exp !== "number"
  ) {
    throw new Error("JWT missing required claims");
  }

  const now = Math.floor(Date.now() / 1000);
  if (payload.exp <= now) throw new Error("JWT expired");
  if (payload.iat > now + 60) throw new Error("JWT iat in the future");

  return payload as JwtClaims;
}

// Shared CORS headers for every Marketify edge function.
//
// Contract: exports `corsHeaders` (Record<string, string>) to splat into
//           every edge function's response and a pre-flight short-circuit.
// Auth:     n/a — the browser reads these before the request runs.
//
// `*` origin is safe here: edge functions authenticate via the
// Authorization: Bearer <marketify_jwt> header, not cookies, so there is no
// ambient-credential risk to guard against with a narrower origin allowlist.

export const corsHeaders: Record<string, string> = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "GET, POST, PATCH, DELETE, OPTIONS",
};

// URL classification + oEmbed fetch for TikTok / Instagram post URLs.
//
// Consumers: submit-video (US-045). Extend here before adding platforms.
//
// Platform detection is based on URL host + path shape — we accept the
// common formats a creator is likely to paste:
//   TikTok:    https://www.tiktok.com/@handle/video/1234567890
//              https://vm.tiktok.com/XXXXXXX/      (share redirect)
//              https://vt.tiktok.com/XXXXXXX/      (share redirect)
//              https://www.tiktok.com/t/XXXXXXX/   (share redirect)
//   Instagram: https://www.instagram.com/p/<code>/
//              https://www.instagram.com/reel/<code>/
//              https://www.instagram.com/tv/<code>/
//
// external_id extraction is best-effort. For canonical TikTok URLs the
// trailing numeric video id is the external_id; for shortlinks we leave
// external_id null and let the oEmbed response (if available) provide it
// via provider-specific fields (currently unused). The
// `submission_reuse_view` in public skips rows with external_id IS NULL,
// so shortlink-only rows simply don't participate in reuse counting until
// the lister paste-flow hands us a canonical URL.
//
// oEmbed endpoints (docs/tech-architecture.md §3h):
//   TikTok:    GET https://www.tiktok.com/oembed?url=<share_url>      (no auth)
//   Instagram: GET https://graph.facebook.com/v<ver>/instagram_oembed (app-token)
//
// Instagram oEmbed requires an app-level Meta token. We do NOT have one
// configured, so IG validation here is regex-shape only; the spec §3h
// notes this requirement. Expand `fetchOembed` once the token is wired.

export type OembedPlatform = "tiktok" | "instagram";

export interface UrlClassification {
  platform: OembedPlatform;
  externalId: string | null;
}

export interface OembedResult {
  thumbnailUrl: string | null;
  authorHandle: string | null;
  raw: Record<string, unknown>;
}

const TIKTOK_CANONICAL_RE =
  /^https:\/\/(?:www\.)?tiktok\.com\/@[A-Za-z0-9._-]+\/video\/(\d+)/i;
const TIKTOK_SHORTLINK_RE =
  /^https:\/\/(?:vm|vt)\.tiktok\.com\/[A-Za-z0-9]+\/?/i;
const TIKTOK_TLINK_RE =
  /^https:\/\/(?:www\.)?tiktok\.com\/t\/[A-Za-z0-9]+\/?/i;

const INSTAGRAM_RE =
  /^https:\/\/(?:www\.)?instagram\.com\/(?:p|reel|tv)\/([A-Za-z0-9_-]+)\/?/i;

export function classifyVideoUrl(url: string): UrlClassification | null {
  if (typeof url !== "string") return null;
  const trimmed = url.trim();
  if (trimmed.length === 0) return null;

  const canon = trimmed.match(TIKTOK_CANONICAL_RE);
  if (canon) {
    return { platform: "tiktok", externalId: canon[1] };
  }
  if (TIKTOK_SHORTLINK_RE.test(trimmed) || TIKTOK_TLINK_RE.test(trimmed)) {
    return { platform: "tiktok", externalId: null };
  }
  const ig = trimmed.match(INSTAGRAM_RE);
  if (ig) {
    return { platform: "instagram", externalId: ig[1] };
  }
  return null;
}

export async function fetchTikTokOembed(
  url: string,
): Promise<OembedResult | null> {
  const endpoint = `https://www.tiktok.com/oembed?url=${encodeURIComponent(url)}`;
  let response: Response;
  try {
    response = await fetch(endpoint, {
      headers: { "User-Agent": "marketify-submit-video/1.0" },
    });
  } catch (_err) {
    // Network failures are treated as "URL could not be validated" at the
    // caller's discretion. Throw fixed-string errors rather than ${err}
    // to avoid leaking internal paths if fetch implementations ever grow
    // diagnostic info.
    throw new Error("TikTok oEmbed fetch failed");
  }
  if (response.status === 404 || response.status === 400) {
    return null;
  }
  if (!response.ok) {
    throw new Error(`TikTok oEmbed HTTP ${response.status}`);
  }
  let data: Record<string, unknown>;
  try {
    data = await response.json();
  } catch {
    throw new Error("TikTok oEmbed returned non-JSON");
  }
  const thumbnailUrl = typeof data.thumbnail_url === "string"
    ? data.thumbnail_url
    : null;
  const authorHandle = extractTikTokAuthorHandle(data);
  return { thumbnailUrl, authorHandle, raw: data };
}

function extractTikTokAuthorHandle(
  data: Record<string, unknown>,
): string | null {
  // TikTok's oEmbed returns `author_unique_id` (canonical handle) and
  // `author_name` (display name). Prefer the unique id; strip any leading
  // @ because our social_links.handle is stored without it.
  const candidates = [data.author_unique_id, data.author_name];
  for (const raw of candidates) {
    if (typeof raw === "string") {
      const h = raw.trim().replace(/^@+/, "");
      if (h.length > 0) return h;
    }
  }
  return null;
}

